Here's a Python script to compute factorials, with both CLI and interactive usage, plus an option to use the built-in math.factorial if you prefer.

#!/usr/bin/env python3
import sys

def factorial(n: int) -> int:
    """Compute non-negative integer factorial iteratively."""
    if n < 0:
        raise ValueError("n must be non-negative")
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

def main():
    import argparse

    parser = argparse.ArgumentParser(description="Compute the factorial of a non-negative integer.")
    parser.add_argument("n", nargs="?", help="non-negative integer to compute factorial for")
    parser.add_argument("--use-math", action="store_true", help="use math.factorial for computation")
    args = parser.parse_args()

    if args.n is not None:
        try:
            n = int(args.n)
        except ValueError:
            print("Error: n must be a non-negative integer.", file=sys.stderr)
            sys.exit(1)
        if n < 0:
            print("Error: n must be a non-negative integer.", file=sys.stderr)
            sys.exit(1)

        if args.use_math:
            import math
            print(math.factorial(n))
        else:
            print(factorial(n))
        return

    # Interactive mode
    try:
        s = input("Enter non-negative integer: ").strip()
        n = int(s)
    except ValueError:
        print("Error: invalid input.", file=sys.stderr)
        sys.exit(1)

    if n < 0:
        print("Error: n must be a non-negative integer.", file=sys.stderr)
        sys.exit(1)

    print(factorial(n))

if __name__ == "__main__":
    main()

Usage:
- CLI: python factorial.py 5 -> prints 120
- CLI with math: python factorial.py 5 --use-math -> prints 120
- Interactive: python factorial.py (then enter a non-negative integer when prompted)

